14	// TestRunBundleFile_PathTraversalRejected covers AC: bundleFile rejects path
15	// traversal (`..`), absolute paths outside the bundle root, and symlink
16	// targets that escape the root.
17	func TestRunBundleFile_PathTraversalRejected(t *testing.T) {
18		workDir, bundleID := setupRunBundleFixture(t)
19		state := stateWithProject(workDir)
20	
21		cases := []struct {
22			name string
23			path string
24		}{
25			{"dotdot prefix", "../../etc/passwd"},
26			{"dotdot mid", "subdir/../../escape.txt"},
27			{"absolute path", "/etc/passwd"},
28			{"absolute under workdir", filepath.Join(workDir, ".ddx", "config.yaml")},
29		}
30	
31		for _, tc := range cases {
32			t.Run(tc.name, func(t *testing.T) {
33				out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, tc.path)
34				if ok || out != nil {
35					t.Fatalf("expected reject for %q, got ok=%v out=%+v", tc.path, ok, out)
36				}
37			})
38		}
39	}
