41	// TestRunBundleFile_SymlinkEscapeRejected creates a symlink inside the
42	// bundle that targets a file outside the root and confirms the resolver
43	// refuses to read it.
44	func TestRunBundleFile_SymlinkEscapeRejected(t *testing.T) {
45		if runtime.GOOS == "windows" {
46			t.Skip("symlinks not portable on windows test runners")
47		}
