169	// TestRunToolCalls_PersistedAtDrain covers AC: tool calls are read from the
170	// persisted SessionIndexEntry.ToolCalls field, NOT parsed from log files at
171	// resolver time. We write a session row directly and confirm the resolver
172	// returns its ToolCalls without scanning any log file.
173	func TestRunToolCalls_PersistedAtDrain(t *testing.T) {
174		workDir := t.TempDir()
175		writeConfig(t, workDir, `version: "1.0"`+"\n")
176		state := stateWithProject(workDir)
177	
178		now := time.Date(2026, 5, 1, 0, 0, 0, 0, time.UTC)
179		entry := agent.SessionIndexEntry{
180			ID:          "sess-tools-001",
181			Harness:     "claude",
182			BillingMode: "paid",
183			StartedAt:   now,
184			ToolCalls: []agent.ToolCallEntry{
185				{Tool: "Read", Input: `{"path":"a"}`, Output: "ok", Duration: 12},
186				{Tool: "Bash", Input: `{"cmd":"ls"}`, Error: "exit 1"},
187			},
188		}
189		if err := agent.AppendSessionIndex(agent.SessionLogDirForWorkDir(workDir), entry, now); err != nil {
190			t.Fatal(err)
191		}
192	
193		calls := state.GetRunToolCallsGraphQL("sess-tools-001")
194		if len(calls) != 2 {
195			t.Fatalf("expected 2 tool calls, got %d", len(calls))
196		}
197		if calls[0].Tool != "Read" || calls[0].Seq != 0 {
